import { useState } from "react";

const LOGO = "";

// Client-side response cache — same input within session skips the API entirely
const _cache = new Map();

const PRICES = {
  studio:       { standard: 5,  hd: 10,  batch: 50  },
  auditor:      { quick:   50,  full:200, deep:  500 },
  intelligence: { analysis:10,  insight:25,whale: 50  },
};

/* ─── tiny helpers ─── */
function Hex() {
  return (
    <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:0,overflow:"hidden",opacity:0.035}}>
      <svg width="100%" height="100%">
        <defs>
          <pattern id="hex" x="0" y="0" width="56" height="48" patternUnits="userSpaceOnUse">
            <polygon points="28,2 52,14 52,34 28,46 4,34 4,14" fill="none" stroke="#A855F7" strokeWidth="0.8"/>
          </pattern>
        </defs>
        <rect width="100%" height="100%" fill="url(#hex)"/>
      </svg>
    </div>
  );
}

function Dots() {
  return (
    <span style={{fontFamily:"monospace"}}>
      {[0,.4,.8].map((d,i)=>(
        <span key={i} style={{animation:`bl 1.2s infinite ${d}s`}}>.</span>
      ))}
    </span>
  );
}

function Badge({amount,label}) {
  return (
    <span style={{display:"inline-flex",alignItems:"center",gap:6,background:"rgba(251,183,36,.12)",border:"1px solid rgba(251,183,36,.4)",borderRadius:4,padding:"4px 10px",fontSize:12,color:"#FBB724",fontFamily:"monospace",fontWeight:700}}>
      ◈ {amount} HENG · {label}
    </span>
  );
}

function Wallet({balance,connected,onConnect}) {
  return (
    <div style={{display:"flex",alignItems:"center",gap:16,background:"rgba(168,85,247,.06)",border:"1px solid rgba(168,85,247,.2)",borderRadius:8,padding:"8px 16px"}}>
      {connected ? (
        <>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{width:8,height:8,borderRadius:"50%",background:"#A855F7",boxShadow:"0 0 8px #A855F7"}}/>
            <span style={{color:"#888",fontSize:12,fontFamily:"monospace"}}>0x3f9…b4d2</span>
          </div>
          <div style={{width:1,height:20,background:"rgba(255,255,255,.1)"}}/>
          <span style={{color:"#FBB724",fontSize:13,fontWeight:700,fontFamily:"monospace"}}>◈ {balance} HENG</span>
        </>
      ) : (
        <button onClick={onConnect} style={{background:"linear-gradient(135deg,#A855F7,#7C3AED)",border:"none",borderRadius:6,padding:"6px 16px",color:"#fff",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"monospace",letterSpacing:1}}>
          CONNECT WALLET
        </button>
      )}
    </div>
  );
}

/* ─── MODULE 1: Studio ─── */
function Studio({balance,onSpend,connected}) {
  const [prompt,setPrompt]=useState("");
  const [tier,setTier]=useState("standard");
  const [loading,setLoading]=useState(false);
  const [result,setResult]=useState(null);
  const [err,setErr]=useState("");
  const costs={standard:5,hd:10,batch:50};
  const labels={standard:"Standard",hd:"HD Image",batch:"NFT Batch"};

  async function run() {
    if(!connected) return setErr("Connect wallet first.");
    if(!prompt.trim()) return setErr("Enter a prompt.");
    const cost=costs[tier];
    if(balance<cost) return setErr(`Need ${cost} HENG.`);
    setErr(""); setLoading(true); setResult(null);
    try {
      // Check client-side cache first
      const cacheKey = `studio:${tier}:${prompt.trim().toLowerCase()}`;
      if (_cache.has(cacheKey)) { onSpend(cost); setResult(_cache.get(cacheKey)); setLoading(false); return; }

      const userMessage = `Generate artwork (${tier}, resolution ${tier==="batch"?"4K×4K":tier==="hd"?"2048×2048":"1024×1024"}): ${prompt.trim()}`;
      const res = await fetch("/api/claude",{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({ module:"studio", userMessage })
      });
      if(!res.ok){ const e=await res.json(); throw new Error(e.error||`HTTP ${res.status}`); }
      const d=await res.json();
      if(d.error) throw new Error(d.error);
      const txt=d.content.map(b=>b.text||"").join("");
      const parsed=JSON.parse(txt.replace(/```json|```/g,"").trim());
      // Inject ipfs_cid and resolution if model omitted them
      if(!parsed.ipfs_cid) parsed.ipfs_cid = "Qm"+Math.random().toString(36).slice(2,14)+"...";
      if(!parsed.resolution) parsed.resolution = tier==="batch"?"4K×4K":tier==="hd"?"2048×2048":"1024×1024";
      _cache.set(cacheKey, parsed);
      onSpend(cost); setResult(parsed);
    } catch(e){ setErr("Error: "+e.message); }
    setLoading(false);
  }

  const pal=result?.palette||["#1a0533","#2d1060","#4c1d95"];
  return (
    <div style={{display:"flex",flexDirection:"column",gap:24}}>
      <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
        {Object.entries(labels).map(([k,l])=>(
          <button key={k} onClick={()=>setTier(k)} style={{padding:"10px 18px",borderRadius:6,cursor:"pointer",border:tier===k?"1px solid #A855F7":"1px solid rgba(255,255,255,.1)",background:tier===k?"rgba(168,85,247,.15)":"rgba(255,255,255,.03)",color:tier===k?"#C084FC":"#666",fontFamily:"monospace",fontSize:12,transition:"all .2s"}}>
            {l} <span style={{color:"#FBB724",fontSize:11}}>◈{costs[k]}</span>
          </button>
        ))}
      </div>
      <textarea value={prompt} onChange={e=>setPrompt(e.target.value)}
        placeholder="Describe your artwork… e.g. 'Cyberpunk dragon holding HENG token, neon Tokyo backdrop'"
        style={{width:"100%",minHeight:100,background:"rgba(0,0,0,.4)",border:"1px solid rgba(168,85,247,.25)",borderRadius:8,padding:14,color:"#E0E0E0",fontFamily:"monospace",fontSize:13,resize:"vertical",outline:"none",boxSizing:"border-box"}}/>
      {err && <div style={{color:"#F87171",fontSize:12,fontFamily:"monospace"}}>⚠ {err}</div>}
      <button onClick={run} disabled={loading} style={{background:loading?"rgba(168,85,247,.1)":"linear-gradient(135deg,rgba(168,85,247,.25),rgba(124,58,237,.2))",border:"1px solid rgba(168,85,247,.5)",borderRadius:8,padding:"14px 28px",color:"#C084FC",fontSize:14,fontFamily:"monospace",fontWeight:700,cursor:loading?"wait":"pointer",letterSpacing:2,alignSelf:"flex-start",transition:"all .3s"}}>
        {loading?<>⟳ GENERATING<Dots/></>:`⊕ GENERATE · ${costs[tier]} HENG`}
      </button>
      {result && (
        <div style={{background:"rgba(0,0,0,.5)",border:"1px solid rgba(168,85,247,.25)",borderRadius:12,padding:24,display:"flex",flexDirection:"column",gap:16}}>
          <div style={{height:200,borderRadius:8,background:`linear-gradient(135deg,${pal[0]},${pal[1]},${pal[2]})`,display:"flex",alignItems:"center",justifyContent:"center",position:"relative",overflow:"hidden"}}>
            <div style={{textAlign:"center",zIndex:2}}>
              <div style={{fontSize:48,marginBottom:8}}>🎨</div>
              <div style={{color:"rgba(255,255,255,.9)",fontSize:16,fontWeight:700}}>{result.title}</div>
              <div style={{color:"rgba(255,255,255,.5)",fontSize:11,marginTop:4}}>{result.resolution}</div>
            </div>
            <div style={{position:"absolute",inset:0,background:"repeating-linear-gradient(45deg,transparent,transparent 10px,rgba(168,85,247,.04) 10px,rgba(168,85,247,.04) 11px)"}}/>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
            <div>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:6}}>DESCRIPTION</div>
              <div style={{color:"#C0C0C0",fontSize:12,lineHeight:1.6}}>{result.description}</div>
            </div>
            <div>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:8}}>NFT TRAITS</div>
              {result.nft_traits?.map((t,i)=>(
                <div key={i} style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                  <span style={{color:"#666",fontSize:11}}>{t.trait}</span>
                  <span style={{color:"#A855F7",fontSize:11,fontFamily:"monospace"}}>{t.value}</span>
                </div>
              ))}
            </div>
          </div>
          <div style={{display:"flex",gap:12,alignItems:"center",flexWrap:"wrap"}}>
            <div style={{color:"#444",fontSize:11,fontFamily:"monospace",flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>IPFS: {result.ipfs_cid}</div>
            <span style={{color:"#FBB724",fontSize:12,fontFamily:"monospace"}}>◈ Floor: {result.estimated_floor}</span>
            <button style={{background:"linear-gradient(135deg,#A855F7,#7C3AED)",border:"none",borderRadius:6,padding:"6px 14px",color:"#fff",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"monospace"}}>MINT NFT →</button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ─── MODULE 2: Auditor ─── */
function Auditor({balance,onSpend,connected}) {
  const [input,setInput]=useState("");
  const [tier,setTier]=useState("quick");
  const [loading,setLoading]=useState(false);
  const [result,setResult]=useState(null);
  const [err,setErr]=useState("");
  const costs={quick:50,full:200,deep:500};
  const labels={quick:"Quick Scan",full:"Full Audit",deep:"Deep Analysis"};
  const riskCol={Low:"#34D399",Medium:"#FBB724",High:"#F87171",Critical:"#EF4444"};
  const sevCol={Critical:"#EF4444",High:"#F87171",Medium:"#FBB724",Low:"#34D399",Info:"#666"};

  async function run() {
    if(!connected) return setErr("Connect wallet first.");
    if(!input.trim()) return setErr("Paste contract code or address.");
    const cost=costs[tier];
    if(balance<cost) return setErr(`Need ${cost} HENG.`);
    setErr(""); setLoading(true); setResult(null);
    try {
      const cacheKey = `auditor:${tier}:${input.trim().slice(0,80)}`;
      if (_cache.has(cacheKey)) { onSpend(cost); setResult(_cache.get(cacheKey)); setLoading(false); return; }

      const userMessage = `${tier.toUpperCase()} scan: ${input.trim()}`;
      const res = await fetch("/api/claude",{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({ module:"auditor", userMessage })
      });
      if(!res.ok){ const e=await res.json(); throw new Error(e.error||`HTTP ${res.status}`); }
      const d=await res.json();
      if(d.error) throw new Error(d.error);
      const txt=d.content.map(b=>b.text||"").join("");
      const parsed=JSON.parse(txt.replace(/```json|```/g,"").trim());
      _cache.set(cacheKey, parsed);
      onSpend(cost); setResult(parsed);
    } catch(e){ setErr("Error: "+e.message); }
    setLoading(false);
  }

  return (
    <div style={{display:"flex",flexDirection:"column",gap:24}}>
      <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
        {Object.entries(labels).map(([k,l])=>(
          <button key={k} onClick={()=>setTier(k)} style={{padding:"10px 18px",borderRadius:6,cursor:"pointer",border:tier===k?"1px solid #EC4899":"1px solid rgba(255,255,255,.1)",background:tier===k?"rgba(236,72,153,.12)":"rgba(255,255,255,.03)",color:tier===k?"#F472B6":"#666",fontFamily:"monospace",fontSize:12,transition:"all .2s"}}>
            {l} <span style={{color:"#FBB724",fontSize:11}}>◈{costs[k]}</span>
          </button>
        ))}
      </div>
      <textarea value={input} onChange={e=>setInput(e.target.value)}
        placeholder={"Paste contract address or Solidity code…\n\nExample:\n0x742d35Cc6634C0532925a3b8D4C9C3e2D7b8f1a3\n\nor:\npragma solidity ^0.8.0;\ncontract Token { ... }"}
        style={{width:"100%",minHeight:140,background:"rgba(0,0,0,.5)",border:"1px solid rgba(236,72,153,.2)",borderRadius:8,padding:14,color:"#E0E0E0",fontFamily:"monospace",fontSize:12,resize:"vertical",outline:"none",boxSizing:"border-box"}}/>
      {err && <div style={{color:"#F87171",fontSize:12,fontFamily:"monospace"}}>⚠ {err}</div>}
      <button onClick={run} disabled={loading} style={{background:loading?"rgba(236,72,153,.1)":"linear-gradient(135deg,rgba(236,72,153,.2),rgba(168,85,247,.15))",border:"1px solid rgba(236,72,153,.45)",borderRadius:8,padding:"14px 28px",color:"#F472B6",fontSize:14,fontFamily:"monospace",fontWeight:700,cursor:loading?"wait":"pointer",letterSpacing:2,alignSelf:"flex-start",transition:"all .3s"}}>
        {loading?<>⟳ SCANNING<Dots/></>:`⊕ AUDIT CONTRACT · ${costs[tier]} HENG`}
      </button>
      {result && (
        <div style={{background:"rgba(0,0,0,.5)",border:"1px solid rgba(236,72,153,.2)",borderRadius:12,padding:24,display:"flex",flexDirection:"column",gap:20}}>
          <div style={{display:"flex",alignItems:"center",gap:24,flexWrap:"wrap"}}>
            <div style={{textAlign:"center"}}>
              <div style={{width:80,height:80,borderRadius:"50%",border:`3px solid ${riskCol[result.risk_level]||"#888"}`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",boxShadow:`0 0 20px ${riskCol[result.risk_level]||"#888"}44`}}>
                <div style={{color:riskCol[result.risk_level]||"#888",fontSize:22,fontWeight:900,fontFamily:"monospace"}}>{result.security_score}</div>
                <div style={{color:"#555",fontSize:9,letterSpacing:1}}>/100</div>
              </div>
            </div>
            <div style={{flex:1}}>
              <div style={{color:"#fff",fontSize:16,fontWeight:700,marginBottom:8}}>{result.contract_name}</div>
              <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                <span style={{padding:"3px 10px",borderRadius:4,fontSize:11,fontFamily:"monospace",background:`${riskCol[result.risk_level]||"#888"}22`,border:`1px solid ${riskCol[result.risk_level]||"#888"}66`,color:riskCol[result.risk_level]||"#888"}}>RISK: {result.risk_level}</span>
                <span style={{padding:"3px 10px",borderRadius:4,fontSize:11,fontFamily:"monospace",background:result.recommendation?.includes("SAFE")?"rgba(52,211,153,.1)":"rgba(248,113,113,.1)",border:`1px solid ${result.recommendation?.includes("SAFE")?"#34D399":"#F87171"}66`,color:result.recommendation?.includes("SAFE")?"#34D399":"#F87171"}}>{result.recommendation}</span>
              </div>
            </div>
          </div>
          <div style={{color:"#999",fontSize:12,lineHeight:1.7,borderLeft:"2px solid rgba(236,72,153,.3)",paddingLeft:12}}>{result.summary}</div>
          {result.issues?.length>0 && (
            <div>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:10}}>ISSUES DETECTED</div>
              {result.issues.map((issue,i)=>(
                <div key={i} style={{background:"rgba(255,255,255,.02)",border:"1px solid rgba(255,255,255,.05)",borderLeft:`3px solid ${sevCol[issue.severity]||"#666"}`,borderRadius:6,padding:"10px 14px",marginBottom:8}}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                    <span style={{color:"#E0E0E0",fontSize:12,fontWeight:600}}>{issue.title}</span>
                    <span style={{color:sevCol[issue.severity]||"#666",fontSize:10,fontFamily:"monospace"}}>[{issue.severity}] {issue.line!=="N/A"?`L${issue.line}`:""}</span>
                  </div>
                  <div style={{color:"#888",fontSize:11}}>{issue.description}</div>
                </div>
              ))}
            </div>
          )}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
            <div>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:8}}>GAS OPTIMIZATIONS</div>
              {result.gas_suggestions?.map((s,i)=><div key={i} style={{color:"#A855F7",fontSize:11,marginBottom:4}}>→ {s}</div>)}
            </div>
            <div>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:8}}>RUG PULL SIGNALS</div>
              {result.rug_pull_signals?.map((s,i)=><div key={i} style={{color:"#FBB724",fontSize:11,marginBottom:4}}>⚑ {s}</div>)}
              <div style={{marginTop:8,color:"#888",fontSize:11}}>
                Liquidity: <span style={{color:result.liquidity_safety==="Locked"?"#34D399":"#F87171"}}>{result.liquidity_safety}</span>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ─── MODULE 3: Intelligence ─── */
function Intelligence({balance,onSpend,connected}) {
  const [input,setInput]=useState("");
  const [tier,setTier]=useState("analysis");
  const [loading,setLoading]=useState(false);
  const [result,setResult]=useState(null);
  const [err,setErr]=useState("");
  const costs={analysis:10,insight:25,whale:50};
  const labels={analysis:"Token Analysis",insight:"AI Trading Insight",whale:"Whale Tracker"};
  const sigCol={BUY:"#34D399",HOLD:"#FBB724",SELL:"#F87171",CAUTION:"#FB923C"};

  async function run() {
    if(!connected) return setErr("Connect wallet first.");
    if(!input.trim()) return setErr("Enter token name or contract.");
    const cost=costs[tier];
    if(balance<cost) return setErr(`Need ${cost} HENG.`);
    setErr(""); setLoading(true); setResult(null);
    try {
      const cacheKey = `intel:${tier}:${input.trim().toLowerCase()}`;
      if (_cache.has(cacheKey)) { onSpend(cost); setResult(_cache.get(cacheKey)); setLoading(false); return; }

      const userMessage = `${tier.toUpperCase()} analysis: ${input.trim()}`;
      const res = await fetch("/api/claude",{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({ module:"intelligence", userMessage })
      });
      if(!res.ok){ const e=await res.json(); throw new Error(e.error||`HTTP ${res.status}`); }
      const d=await res.json();
      if(d.error) throw new Error(d.error);
      const txt=d.content.map(b=>b.text||"").join("");
      const parsed=JSON.parse(txt.replace(/```json|```/g,"").trim());
      _cache.set(cacheKey, parsed);
      onSpend(cost); setResult(parsed);
    } catch(e){ setErr("Error: "+e.message); }
    setLoading(false);
  }

  function MiniChart({points}) {
    if(!points?.length) return null;
    const mx=Math.max(...points),mn=Math.min(...points),rng=mx-mn||1,w=220,h=64;
    const xs=points.map((_,i)=>(i/(points.length-1))*w);
    const ys=points.map(v=>h-((v-mn)/rng)*(h-10)-5);
    const path=xs.map((x,i)=>`${i===0?"M":"L"}${x} ${ys[i]}`).join(" ");
    const up=points[points.length-1]>=points[0];
    return(
      <svg width={w} height={h} style={{display:"block"}}>
        <defs>
          <linearGradient id="cg" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={up?"#A855F7":"#F87171"} stopOpacity="0.35"/>
            <stop offset="100%" stopColor={up?"#A855F7":"#F87171"} stopOpacity="0"/>
          </linearGradient>
        </defs>
        <path d={`${path} L${xs[xs.length-1]} ${h} L0 ${h}Z`} fill="url(#cg)"/>
        <path d={path} fill="none" stroke={up?"#A855F7":"#F87171"} strokeWidth="2.5" strokeLinecap="round"/>
      </svg>
    );
  }

  return (
    <div style={{display:"flex",flexDirection:"column",gap:24}}>
      <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
        {Object.entries(labels).map(([k,l])=>(
          <button key={k} onClick={()=>setTier(k)} style={{padding:"10px 18px",borderRadius:6,cursor:"pointer",border:tier===k?"1px solid #FBB724":"1px solid rgba(255,255,255,.1)",background:tier===k?"rgba(251,183,36,.1)":"rgba(255,255,255,.03)",color:tier===k?"#FBB724":"#666",fontFamily:"monospace",fontSize:12,transition:"all .2s"}}>
            {l} <span style={{color:"#FBB724",fontSize:11}}>◈{costs[k]}</span>
          </button>
        ))}
      </div>
      <input value={input} onChange={e=>setInput(e.target.value)}
        placeholder="Token name or contract address… e.g. HENG, 0x742d35Cc…"
        style={{width:"100%",background:"rgba(0,0,0,.4)",border:"1px solid rgba(251,183,36,.25)",borderRadius:8,padding:14,color:"#E0E0E0",fontFamily:"monospace",fontSize:13,outline:"none",boxSizing:"border-box"}}/>
      {err && <div style={{color:"#F87171",fontSize:12,fontFamily:"monospace"}}>⚠ {err}</div>}
      <button onClick={run} disabled={loading} style={{background:loading?"rgba(251,183,36,.1)":"linear-gradient(135deg,rgba(251,183,36,.2),rgba(168,85,247,.15))",border:"1px solid rgba(251,183,36,.45)",borderRadius:8,padding:"14px 28px",color:"#FBB724",fontSize:14,fontFamily:"monospace",fontWeight:700,cursor:loading?"wait":"pointer",letterSpacing:2,alignSelf:"flex-start",transition:"all .3s"}}>
        {loading?<>⟳ ANALYZING<Dots/></>:`⊕ ANALYZE TOKEN · ${costs[tier]} HENG`}
      </button>
      {result && (
        <div style={{background:"rgba(0,0,0,.5)",border:"1px solid rgba(251,183,36,.2)",borderRadius:12,padding:24,display:"flex",flexDirection:"column",gap:20}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:12}}>
            <div>
              <div style={{color:"#fff",fontSize:22,fontWeight:900}}>{result.token_name} <span style={{color:"#555"}}>({result.ticker})</span></div>
              <div style={{color:"#555",fontSize:11,fontFamily:"monospace",marginTop:2}}>{result.contract}</div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{color:"#fff",fontSize:20,fontWeight:700}}>{result.price_usd}</div>
              <div style={{color:result.price_change_24h?.startsWith("+")?"#34D399":"#F87171",fontSize:13}}>{result.price_change_24h} (24h)</div>
            </div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12}}>
            {[{l:"MKT CAP",v:result.market_cap},{l:"VOL 24H",v:result.volume_24h},{l:"LIQUIDITY",v:result.liquidity}].map(s=>(
              <div key={s.l} style={{background:"rgba(255,255,255,.03)",border:"1px solid rgba(255,255,255,.06)",borderRadius:8,padding:12,textAlign:"center"}}>
                <div style={{color:"#444",fontSize:9,letterSpacing:2,marginBottom:4}}>{s.l}</div>
                <div style={{color:"#A855F7",fontSize:14,fontWeight:700,fontFamily:"monospace"}}>{s.v}</div>
              </div>
            ))}
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr auto",gap:24,alignItems:"center"}}>
            <div>
              <div style={{color:"#444",fontSize:10,letterSpacing:2,marginBottom:8}}>PRICE ACTION (10 INTERVALS)</div>
              <MiniChart points={result.chart_points}/>
            </div>
            <div style={{textAlign:"center"}}>
              <div style={{width:90,height:90,borderRadius:"50%",border:`3px solid ${sigCol[result.ai_signal]||"#888"}`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",boxShadow:`0 0 24px ${sigCol[result.ai_signal]||"#888"}44`,background:`${sigCol[result.ai_signal]||"#888"}11`}}>
                <div style={{color:"#666",fontSize:9,letterSpacing:1}}>AI</div>
                <div style={{color:sigCol[result.ai_signal]||"#888",fontSize:18,fontWeight:900}}>{result.ai_signal}</div>
              </div>
              <div style={{color:"#555",fontSize:10,marginTop:6}}>{result.sentiment}</div>
            </div>
          </div>
          <div>
            <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:8}}>AI REASONING</div>
            {result.signal_reasons?.map((r,i)=>(
              <div key={i} style={{display:"flex",gap:8,marginBottom:6}}>
                <span style={{color:sigCol[result.ai_signal]||"#888",fontSize:11}}>▸</span>
                <span style={{color:"#C0C0C0",fontSize:12}}>{r}</span>
              </div>
            ))}
          </div>
          {result.whale_activity?.length>0 && (
            <div>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:8}}>🐋 WHALE ACTIVITY</div>
              {result.whale_activity.map((w,i)=>(
                <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 12px",background:"rgba(255,255,255,.02)",border:"1px solid rgba(255,255,255,.05)",borderRadius:6,marginBottom:6}}>
                  <span style={{color:"#777",fontSize:11,fontFamily:"monospace"}}>{w.wallet}</span>
                  <span style={{color:w.action==="SELL"?"#F87171":"#34D399",fontSize:11,fontWeight:700}}>{w.action}</span>
                  <span style={{color:"#FBB724",fontSize:11}}>{w.amount}</span>
                  <span style={{color:"#444",fontSize:10}}>{w.time}</span>
                </div>
              ))}
            </div>
          )}
          <div style={{display:"flex",gap:16,flexWrap:"wrap"}}>
            <div style={{flex:1}}>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:6}}>RUG SIGNALS</div>
              {result.rug_signals?.map((s,i)=><div key={i} style={{color:s.includes("Clean")?"#34D399":"#F87171",fontSize:11,marginBottom:3}}>⚑ {s}</div>)}
            </div>
            <div>
              <div style={{color:"#555",fontSize:10,letterSpacing:2,marginBottom:6}}>SELL PRESSURE</div>
              <span style={{padding:"4px 12px",borderRadius:4,fontSize:12,fontFamily:"monospace",color:result.sell_pressure==="Low"?"#34D399":result.sell_pressure==="High"?"#F87171":"#FBB724",border:"1px solid currentColor",background:result.sell_pressure==="Low"?"rgba(52,211,153,.1)":result.sell_pressure==="High"?"rgba(248,113,113,.1)":"rgba(251,183,36,.1)"}}>{result.sell_pressure}</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* ─── ROOT APP ─── */
const MODULES = [
  {id:"studio",      icon:"✦", num:"01", title:"HENG AI Studio",           sub:"Image Generator & NFT Creator",  accent:"#A855F7", soft:"rgba(168,85,247,.15)", desc:"Generate AI images, NFT artwork, and marketing graphics. Mint directly on MUD Network.",         tags:["Image Gen","NFT Mint","Meme Coins"]},
  {id:"auditor",     icon:"⬡", num:"02", title:"Smart Contract Auditor",    sub:"Security Analysis Engine",       accent:"#EC4899", soft:"rgba(236,72,153,.12)", desc:"AI-powered vulnerability scanner. Detect rug pulls, reentrancy risks, and gas inefficiencies.", tags:["Security","Rug Pull","Gas Audit"]},
  {id:"intelligence",icon:"◇", num:"03", title:"Token Intelligence",         sub:"On-Chain Trading AI",            accent:"#FBB724", soft:"rgba(251,183,36,.10)", desc:"Track price action, whale movements, and liquidity signals. Get AI buy/sell signals.",          tags:["Price AI","Whale Track","Rug Signals"]},
];

export default function App() {
  const [active,setActive]=useState(null);
  const [connected,setConnected]=useState(false);
  const [balance,setBalance]=useState(1000);
  const [log,setLog]=useState([]);

  function spend(amt){ setBalance(b=>b-amt); setLog(l=>[{amt,t:new Date().toLocaleTimeString(),mod:active},...l.slice(0,9)]); }
  const mod=MODULES.find(m=>m.id===active);

  return (
    <div style={{minHeight:"100vh",background:"#06030F",color:"#E0E0E0",fontFamily:"'Segoe UI',system-ui,sans-serif",position:"relative",overflowX:"hidden"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Space+Mono:wght@400;700&display=swap');
        *{box-sizing:border-box}
        @keyframes bl{0%,100%{opacity:1}50%{opacity:0}}
        @keyframes pu{0%,100%{opacity:.5;transform:scale(1)}50%{opacity:1;transform:scale(1.04)}}
        @keyframes fu{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
        @keyframes gp{0%,88%,100%{opacity:0}89%,91%{opacity:1}}
        @keyframes gq{0%,91%,100%{opacity:0}92%,94%{opacity:1}}
        .ch{transition:all .3s;cursor:pointer}.ch:hover{transform:translateY(-4px)}
        ::-webkit-scrollbar{width:4px}
        ::-webkit-scrollbar-track{background:#06030F}
        ::-webkit-scrollbar-thumb{background:rgba(168,85,247,.4);border-radius:2px}
      `}</style>

      <Hex/>
      {/* ambient glows */}
      <div style={{position:"fixed",top:"5%",left:"3%",width:350,height:350,borderRadius:"50%",background:"radial-gradient(circle,rgba(168,85,247,.07),transparent 70%)",pointerEvents:"none",zIndex:0}}/>
      <div style={{position:"fixed",bottom:"15%",right:"3%",width:400,height:400,borderRadius:"50%",background:"radial-gradient(circle,rgba(124,58,237,.05),transparent 70%)",pointerEvents:"none",zIndex:0}}/>
      <div style={{position:"fixed",top:"50%",left:"50%",transform:"translate(-50%,-50%)",width:600,height:600,borderRadius:"50%",background:"radial-gradient(circle,rgba(88,28,135,.04),transparent 70%)",pointerEvents:"none",zIndex:0}}/>

      {/* ── HEADER ── */}
      <header style={{position:"sticky",top:0,zIndex:100,background:"rgba(6,3,15,.93)",backdropFilter:"blur(24px)",borderBottom:"1px solid rgba(168,85,247,.12)",padding:"0 32px",height:64,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div style={{display:"flex",alignItems:"center",gap:16}}>
          {active && (
            <button onClick={()=>setActive(null)} style={{background:"none",border:"1px solid rgba(255,255,255,.1)",borderRadius:6,padding:"6px 12px",color:"#666",cursor:"pointer",fontSize:12,fontFamily:"monospace"}}>
              ← BACK
            </button>
          )}
          <div style={{display:"flex",alignItems:"center",gap:12}}>
            <img src={`data:image/jpeg;base64,${LOGO}`} alt="HENG AI" style={{width:40,height:40,borderRadius:10,objectFit:"cover",border:"1px solid rgba(168,85,247,.35)",boxShadow:"0 0 12px rgba(168,85,247,.25)"}}/>
            <div>
              <div style={{fontSize:14,fontWeight:700,letterSpacing:3,fontFamily:"'Bebas Neue',sans-serif",color:"#E8E8E8"}}>HENG AI PROTOCOL</div>
              <div style={{fontSize:9,color:"#444",letterSpacing:2,fontFamily:"monospace"}}>MUD NETWORK · ON-CHAIN AI</div>
            </div>
          </div>
        </div>
        <Wallet balance={balance} connected={connected} onConnect={()=>setConnected(true)}/>
      </header>

      <main style={{position:"relative",zIndex:2,padding:"0 32px 80px",maxWidth:1100,margin:"0 auto"}}>
        {!active ? (
          /* ── LANDING ── */
          <div style={{animation:"fu .6s ease both"}}>
            {/* hero */}
            <div style={{textAlign:"center",padding:"80px 0 60px"}}>
              <div style={{fontSize:11,letterSpacing:4,color:"#A855F7",fontFamily:"monospace",marginBottom:20}}>◈ POWERED BY MUD NETWORK BLOCKCHAIN ◈</div>

              {/* logo hero */}
              <div style={{position:"relative",display:"inline-block",marginBottom:28}}>
                <img src={`data:image/jpeg;base64,${LOGO}`} alt="HENG AI" style={{width:108,height:108,borderRadius:26,objectFit:"cover",border:"2px solid rgba(168,85,247,.5)",boxShadow:"0 0 48px rgba(168,85,247,.35),0 0 80px rgba(124,58,237,.2)"}}/>
                <div style={{position:"absolute",inset:-6,borderRadius:32,border:"1px solid rgba(168,85,247,.25)",animation:"pu 2.5s ease-in-out infinite"}}/>
                <div style={{position:"absolute",inset:-14,borderRadius:40,border:"1px solid rgba(168,85,247,.1)",animation:"pu 2.5s ease-in-out infinite .6s"}}/>
              </div>

              <h1 style={{fontSize:"clamp(44px,8vw,84px)",fontFamily:"'Bebas Neue',sans-serif",letterSpacing:6,lineHeight:.95,margin:"0 0 24px",color:"#fff",position:"relative",display:"inline-block"}}>
                <span style={{position:"relative",display:"inline-block"}}>
                  HENG AI
                  <span style={{position:"absolute",top:0,left:0,color:"#A855F7",animation:"gp 4s infinite",clipPath:"polygon(0 28%,100% 28%,100% 48%,0 48%)",transform:"translateX(-2px)",pointerEvents:"none"}}>HENG AI</span>
                  <span style={{position:"absolute",top:0,left:0,color:"#EC4899",animation:"gq 4s infinite",clipPath:"polygon(0 54%,100% 54%,100% 74%,0 74%)",transform:"translateX(2px)",pointerEvents:"none"}}>HENG AI</span>
                </span>
                <br/>
                <span style={{color:"#A855F7",letterSpacing:8}}>PROTOCOL</span>
              </h1>

              <p style={{color:"#666",fontSize:14,maxWidth:480,margin:"0 auto 40px",lineHeight:1.85,fontFamily:"monospace"}}>
                One on-chain AI hub for builders, traders &amp; creators.<br/>Every action powered by HENG tokens on MUD Network.
              </p>

              {!connected && (
                <button onClick={()=>setConnected(true)} style={{background:"linear-gradient(135deg,#A855F7,#7C3AED)",border:"none",borderRadius:8,padding:"14px 40px",color:"#fff",fontWeight:700,fontSize:14,cursor:"pointer",fontFamily:"monospace",letterSpacing:2,boxShadow:"0 0 32px rgba(168,85,247,.4)"}}>
                  CONNECT WALLET TO BEGIN
                </button>
              )}
            </div>

            {/* module cards */}
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(300px,1fr))",gap:24}}>
              {MODULES.map((m,i)=>(
                <div key={m.id} onClick={()=>setActive(m.id)} className="ch"
                  style={{background:"rgba(255,255,255,.025)",border:"1px solid rgba(255,255,255,.06)",borderTop:`2px solid ${m.accent}`,borderRadius:12,padding:28,animation:`fu .6s ease ${i*.15}s both`,position:"relative",overflow:"hidden"}}>
                  <div style={{position:"absolute",top:20,right:20,fontSize:52,fontFamily:"'Bebas Neue',sans-serif",color:`${m.accent}0D`,lineHeight:1,userSelect:"none"}}>{m.num}</div>
                  <div style={{width:44,height:44,borderRadius:10,background:m.soft,border:`1px solid ${m.accent}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,color:m.accent,marginBottom:16}}>{m.icon}</div>
                  <div style={{fontSize:16,fontWeight:700,marginBottom:4,fontFamily:"monospace",color:"#fff"}}>{m.title}</div>
                  <div style={{fontSize:11,color:m.accent,letterSpacing:1,marginBottom:12,fontFamily:"monospace"}}>{m.sub}</div>
                  <div style={{fontSize:13,color:"#777",lineHeight:1.75,marginBottom:18}}>{m.desc}</div>
                  <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:18}}>
                    {m.tags.map(t=><span key={t} style={{padding:"3px 8px",borderRadius:4,fontSize:10,background:`${m.accent}10`,border:`1px solid ${m.accent}2E`,color:m.accent,fontFamily:"monospace"}}>{t}</span>)}
                  </div>
                  <div style={{display:"flex",alignItems:"center",gap:6,color:m.accent,fontSize:12,fontFamily:"monospace"}}>
                    <span>LAUNCH MODULE</span><span>→</span>
                  </div>
                </div>
              ))}
            </div>

            {/* stats bar */}
            <div style={{marginTop:56,display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:1,background:"rgba(168,85,247,.08)",border:"1px solid rgba(168,85,247,.1)",borderRadius:12,overflow:"hidden"}}>
              {[{l:"HENG Token",v:"◈ 1,000"},{l:"AI Modules",v:"3"},{l:"Network",v:"MUD"},{l:"Status",v:"● LIVE"}].map(s=>(
                <div key={s.l} style={{background:"rgba(6,3,15,.88)",padding:"22px 16px",textAlign:"center"}}>
                  <div style={{color:"#A855F7",fontSize:20,fontWeight:700,fontFamily:"monospace",marginBottom:4}}>{s.v}</div>
                  <div style={{color:"#383838",fontSize:10,letterSpacing:2}}>{s.l}</div>
                </div>
              ))}
            </div>
          </div>
        ) : (
          /* ── MODULE VIEW ── */
          <div style={{animation:"fu .4s ease both",paddingTop:40}}>
            <div style={{marginBottom:32}}>
              <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:14}}>
                <div style={{width:44,height:44,borderRadius:10,background:mod.soft,border:`1px solid ${mod.accent}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,color:mod.accent}}>{mod.icon}</div>
                <div>
                  <h2 style={{margin:0,fontFamily:"'Bebas Neue',sans-serif",letterSpacing:3,fontSize:30,color:"#fff"}}>{mod.title}</h2>
                  <div style={{color:mod.accent,fontSize:11,fontFamily:"monospace",letterSpacing:2}}>{mod.sub}</div>
                </div>
              </div>
              <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                {Object.entries(PRICES[active]||{}).map(([k,v])=><Badge key={k} amount={v} label={k.toUpperCase()}/>)}
              </div>
            </div>

            <div style={{background:"rgba(255,255,255,.02)",border:`1px solid ${mod.accent}20`,borderTop:`2px solid ${mod.accent}`,borderRadius:12,padding:32}}>
              {active==="studio"      && <Studio       balance={balance} onSpend={spend} connected={connected}/>}
              {active==="auditor"     && <Auditor      balance={balance} onSpend={spend} connected={connected}/>}
              {active==="intelligence"&& <Intelligence balance={balance} onSpend={spend} connected={connected}/>}
            </div>

            {/* tx log */}
            {log.filter(t=>t.mod===active).length>0 && (
              <div style={{marginTop:24}}>
                <div style={{color:"#2a2a2a",fontSize:10,letterSpacing:2,marginBottom:8,fontFamily:"monospace"}}>TRANSACTION LOG</div>
                {log.filter(t=>t.mod===active).slice(0,5).map((t,i)=>(
                  <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"6px 12px",fontFamily:"monospace",fontSize:11,color:"#383838",borderBottom:"1px solid rgba(255,255,255,.02)"}}>
                    <span>⊕ HENG SERVICE FEE</span>
                    <span style={{color:"#FBB724"}}>-{t.amt} HENG</span>
                    <span>{t.t}</span>
                    <span style={{color:"#A855F7"}}>✓ CONFIRMED</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}
